oxy_webhelp_navlinks = {"custom_agents_deployed_agent_cloud-d30753e51642":{"topics":[{"title":"Understand how model gateways work","shortdesc":"<p class=\"shortdesc\">Model gateways are the fundamental infrastructure components that enable <span class=\"ph\">Agent Cloud<\/span> to govern, monitor, and secure your AI agent         interactions.<\/p>","href":"agent_cloud\/understand_how_model_gateways_work.html","attributes":{"data-id":"understand_how_model_gateways_work"},"menu":{"hasChildren":false},"tocID":"understand_how_model_gateways_work-d30753e51661","topics":[]},{"title":"Prerequisites for using custom agents with <span class=\"ph\">Agent Cloud<\/span>","shortdesc":"<p class=\"shortdesc\">Before onboarding <span class=\"ph\">Agent Cloud<\/span>, you must ensure that your environment         meets the required account, network, and configuration prerequisites.<\/p>","href":"agent_cloud\/prerequisites_custom_agents_agent_cloud.html","attributes":{"data-id":"prerequisites_custom_agents_agent_cloud"},"menu":{"hasChildren":false},"tocID":"prerequisites_custom_agents_agent_cloud-d30753e51675","topics":[]},{"title":"Custom agents with the built-in <span class=\"ph\">Agent Cloud<\/span> model gateway","shortdesc":"<p class=\"shortdesc\">Use the Rubrik-managed model gateway when you want Rubrik to operate the gateway infrastructure. After configuring the gateway in RSC, your agent developers replace the direct LLM endpoint in their agent code with the Agent Cloud gateway endpoint.<\/p>","href":"agent_cloud\/custom_agents_built_in_model_gateway.html","attributes":{"data-id":"custom_agents_built_in_model_gateway"},"menu":{"hasChildren":false},"tocID":"custom_agents_built_in_model_gateway-d30753e51691","next":"custom_agents_built_in_model_gateway-d30753e51691"},{"title":"Custom agents with existing model gateways","shortdesc":"<p class=\"shortdesc\">Use an existing model gateway when you already operate gateway infrastructure and want to keep it, or when your agents call LLM providers not supported by the built-in gateway. Agent Cloud connects to your existing gateway by receiving event callbacks from a plugin.<\/p>","href":"agent_cloud\/custom_agents_existing_model_gateways.html","attributes":{"data-id":"custom_agents_existing_model_gateways"},"menu":{"hasChildren":false},"tocID":"custom_agents_existing_model_gateways-d30753e51774","next":"custom_agents_existing_model_gateways-d30753e51774"}]}};